		function scal(scalfactor) {
		
			cont.scaleX = scalfactor;
		
			cont.scaleY = scalfactor;
		
			if (scaleFac > scalfactor) { //scale is down
		
				repositionContainer();
			}
		
			scaleFac = scalfactor;
		
		
		
		}
		
