		function toreset(evt) {
		
		
			cont.regX = cont.origin_regX;
			cont.regY = cont.origin_regY;
		
			cont.scaleX = 1;
			cont.scaleY = 1;
		
		
			scaleFac = 0;
		
			cont.x = firstwidth / 2 + offsetX;
			cont.y = firstheight / 2 + offsetY;
		
			that.slider.resetTrk();
		
		}
		
		cont.toreset = toreset;
		
		function repositionContainer() {
		
		
		
			console.log("cont.x " + cont.x);
		
			var diff = (cont.x - 413.75);
		
			if (scaleFac > 1.5) diff *= 0.1 * scaleFac;
		
			//cont.x = diff > 1 ? cont.x + diff * (1 / ((scaleFac + 1) * 3)) : 413.75;
		
			cont.x = Math.abs(diff) > 2 ? cont.x - diff * (1 / ((scaleFac + 1) * 4)) : firstwidth / 2 + offsetX;;
		
		
			console.log("diff x : " + diff + " cont.x plus  " + -1 * diff * (1 / ((scaleFac + 1) * 3)));
		
		
		
			console.log("cont.y " + scaleFac);
		
			var diff = (cont.y - 227);
		
			if (scaleFac > 1.5) diff *= 0.1 * scaleFac;
		
			cont.y = Math.abs(diff) > 2 ? cont.y - diff * (1 / ((scaleFac + 1) * 4)) : firstheight / 2 + offsetY;
		
		
			//console.log("diff y : " + diff + " cont.y plus  " + diff * 1 / (scaleFac  / 0.1));
		
		}
		
		
